import express, { Express } from 'express';
import cors from 'cors';
import helmet from 'helmet';
import compression from 'compression';
import { rateLimit } from 'express-rate-limit';
import { pinoHttp } from 'pino-http';
import { router } from './routes';
import { errorHandler } from './middleware/errorHandler';
import { notFoundHandler } from './middleware/notFound';
import { config } from './config';

export function createApp(): Express {
  const app = express();

  // Trust proxy for rate-limiting behind reverse proxy
  app.set('trust proxy', 1);

  // Security headers
  app.use(helmet());

  // CORS
  app.use(cors({
    origin: config.corsOrigins,
    credentials: true,
  }));

  // Compression
  app.use(compression());

  // Body parsing
  app.use(express.json({ limit: '10kb' }));
  app.use(express.urlencoded({ extended: true, limit: '10kb' }));

  // Logging
  app.use(pinoHttp({
    logger: config.logger,
    autoLogging: true,
    redact: ['req.headers.authorization', 'req.query.token'],
  }));

  // Rate limiting
  app.use(rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 100,
    standardHeaders: true,
    legacyHeaders: false,
  }));

  // Health check (before auth)
  app.get('/health', (_req, res) => {
    res.json({ status: 'ok', timestamp: new Date().toISOString() });
  });

  // API routes
  app.use('/api/v1', router);

  // 404 handler
  app.use(notFoundHandler);

  // Error handler (must be last)
  app.use(errorHandler);

  return app;
}

// routes/index.ts
import { Router } from 'express';
import usersRouter from './users.routes';
import ordersRouter from './orders.routes';
import { authenticate } from '../middleware/auth';

const router = Router();

router.use('/users', authenticate, usersRouter);
router.use('/orders', authenticate, ordersRouter);

export { router };

// routes/users.routes.ts
import { Router } from 'express';
import { userController } from '../controllers/users.controller';
import { validateAll } from '../middleware/validate';
import { CreateUserSchema, UpdateUserSchema } from '../schemas/users';

const router = Router();

router.get('/', userController.getUsers);
router.get('/:id', userController.getUser);
router.post('/', validateAll({ body: CreateUserSchema }), userController.createUser);
router.patch('/:id', validateAll({ body: UpdateUserSchema }), userController.updateUser);
router.delete('/:id', userController.deleteUser);

export default router;

// controllers/users.controller.ts
import { Request, Response, NextFunction } from 'express';
import { userService } from '../services/users.service';
import { asyncHandler } from '../utils/asyncHandler';

export const userController = {
  getUsers: asyncHandler(async (req, res) => {
    const users = await userService.getUsers();
    res.json(users);
  }),

  getUser: asyncHandler(async (req, res) => {
    const user = await userService.getUser(req.params.id);
    if (!user) return res.status(404).json({ error: 'Not found' });
    res.json(user);
  }),

  createUser: asyncHandler(async (req, res) => {
    const user = await userService.createUser(req.body);
    res.status(201).json(user);
  }),
};

// services/users.service.ts
import { db } from '../lib/db';
import type { CreateUserInput } from '../schemas/users';

export const userService = {
  async getUsers() {
    return db.user.findMany();
  },

  async getUser(id: string) {
    return db.user.findUnique({ where: { id } });
  },

  async createUser(data: CreateUserInput) {
    return db.user.create({ data });
  },
};

// schemas/users.ts
import { z } from 'zod';

export const CreateUserSchema = z.object({
  name: z.string().min(1),
  email: z.string().email(),
});

export const UpdateUserSchema = z.object({
  name: z.string().min(1).optional(),
  email: z.string().email().optional(),
});

export type CreateUserInput = z.infer<typeof CreateUserSchema>;
export type UpdateUserInput = z.infer<typeof UpdateUserSchema>;

// middleware/validate.ts
import { Request, Response, NextFunction } from 'express';
import { z, ZodSchema } from 'zod';
import { AppError } from '../utils/errors';

interface ValidationSchemas {
  body?: ZodSchema;
  params?: ZodSchema;
  query?: ZodSchema;
}

export function validateAll(schemas: ValidationSchemas) {
  return (req: Request, _res: Response, next: NextFunction) => {
    try {
      if (schemas.body) req.body = schemas.body.parse(req.body);
      if (schemas.params) req.params = schemas.params.parse(req.params);
      if (schemas.query) req.query = schemas.query.parse(req.query);
      next();
    } catch (error) {
      if (error instanceof z.ZodError) {
        throw new AppError(
          400,
          'Validation failed',
          error.flatten().fieldErrors,
        );
      }
      throw error;
    }
  };
}

// utils/errors.ts
export class AppError extends Error {
  constructor(
    public statusCode: number,
    public message: string,
    public details?: unknown,
  ) {
    super(message);
  }
}

// middleware/errorHandler.ts
import { Request, Response, NextFunction } from 'express';
import { AppError } from '../utils/errors';
import { logger } from '../utils/logger';

export function errorHandler(
  error: unknown,
  _req: Request,
  res: Response,
  _next: NextFunction,
): void {
  const appError = error instanceof AppError
    ? error
    : new AppError(500, 'Internal Server Error');

  logger.error({
    statusCode: appError.statusCode,
    message: appError.message,
    details: appError.details,
    stack: error instanceof Error ? error.stack : undefined,
  });

  res.status(appError.statusCode).json({
    error: appError.message,
    ...(appError.details && { details: appError.details }),
  });
}

// server.ts (graceful shutdown)
import http from 'node:http';
import { createApp } from './app';
import { config } from './config';
import { logger } from './utils/logger';

const app = createApp();
const server = http.createServer(app);

function shutdown(signal: string) {
  logger.info(`${signal} received, shutting down gracefully`);

  server.close(() => {
    logger.info('HTTP server closed');
    process.exit(0);
  });

  // Force close after 30s
  setTimeout(() => {
    logger.error('Could not close connections in time, forcefully shutting down');
    process.exit(1);
  }, 30000);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

server.listen(config.port, () => {
  logger.info(`Server running on port ${config.port}`);
});

// types/express.d.ts
import type { Request } from 'express';

interface JwtPayload {
  userId: string;
  email: string;
}

declare global {
  namespace Express {
    interface Request {
      user?: JwtPayload;
    }
  }
}

// middleware/auth.ts
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { AppError } from '../utils/errors';
import { config } from '../config';

export function authenticate(
  req: Request,
  _res: Response,
  next: NextFunction,
): void {
  try {
    const authHeader = req.headers.authorization;

    if (!authHeader?.startsWith('Bearer ')) {
      throw new AppError(401, 'Missing authorization header');
    }

    const token = authHeader.slice(7);
    const payload = jwt.verify(token, config.jwtSecret) as JwtPayload;

    req.user = payload;
    next();
  } catch (error) {
    if (error instanceof jwt.JsonWebTokenError) {
      throw new AppError(401, 'Invalid token');
    }
    throw error;
  }
}

import http from 'node:http';
import { db } from './lib/db';
import { redis } from './lib/redis';
import { logger } from './utils/logger';

const server = http.createServer(app);

function shutdown(signal: string) {
  logger.info(`${signal} received, shutting down gracefully`);

  server.close(async () => {
    logger.info('HTTP server closed, draining connections');

    // Drain connections
    try {
      await db.$disconnect();
      logger.info('Database disconnected');
    } catch (err) {
      logger.error('Error disconnecting database', err);
    }

    try {
      await redis.quit();
      logger.info('Redis disconnected');
    } catch (err) {
      logger.error('Error disconnecting Redis', err);
    }

    logger.info('All connections closed, exiting');
    process.exit(0);
  });

  // Force close after 30s
  setTimeout(() => {
    logger.error('Could not close connections in time, forcefully shutting down');
    process.exit(1);
  }, 30000);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

server.listen(config.port, () => {
  logger.info(`Server running on port ${config.port}`);
});
